$txt['smfblog_by'] = 'by';
$txt['smfblog_subject'] = 'Subject';
$txt['smfblog_re'] = 'Re: ';
$txt['smfblog_shortcuts'] = 'shortcuts: hit alt+s to submit/post or alt+p to preview';
